const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const text = item.json.text || item.json.snippet || item.json.body || '';
    const subject = item.json.subject || '';
    const messageId = item.json.id || item.json.messageId || '';
    const threadId = item.json.threadId || '';

    // Parse Shopify key-value format
    // Fields come as "Label:\nValue\n" pairs
    const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
    const fields = {};
    let currentKey = null;

    for (const line of lines) {
      // Skip the header line
      if (line.includes('received a new message from')) continue;

      // Check if this line is a label (ends with colon)
      if (line.endsWith(':') && !line.includes('@') && !line.includes('//')) {
        currentKey = line.slice(0, -1).toLowerCase().trim();
      } else if (currentKey) {
        // Skip broken Shopify template variables
        if (line.includes('%{') || line.includes('creation_date')) continue;
        // This is the value for the current key
        if (!fields[currentKey]) {
          fields[currentKey] = line;
        }
        currentKey = null;
      }
    }

    const fullName = fields['name'] || '';
    const email = fields['email'] || '';
    const phone = fields['phone'] || '';
    const body = fields['body'] || '';
    const ridingSince = fields['riding since'] || '';
    const countryCode = fields['country code'] || '';

    if (!email || !email.includes('@')) continue;
    // Skip if the email is freedomryder's own (test submissions)
    if (email.toLowerCase().includes('freedomryder.com')) continue;

    const firstName = fullName.split(' ')[0] || 'there';

    // Detect veteran inquiry from body content or form source
    const combinedText = (body + ' ' + subject + ' ' + (fields['inquiry type'] || '')).toLowerCase();
    const isVeteran = combinedText.includes('veteran') || combinedText.includes('va fund') || combinedText.includes('va-fund');

    results.push({
      json: {
        fullName,
        firstName,
        email: email.toLowerCase(),
        phone,
        state: '',
        ridingGoal: ridingSince || body,
        height: '',
        weight: '',
        inquiryType: isVeteran ? 'veteran' : 'general',
        originalSubject: subject,
        messageId,
        threadId
      }
    });
  } catch (error) {
    continue;
  }
}

if (results.length === 0) {
  throw new Error('Could not parse a valid lead from the Shopify contact form email.');
}

return results;
